    id: "20",
    name: "Avv. Claudio Iafrate",
    title: "Senior Associate",
    role: "Senior Associate",
    specializations: ["diritto-civile-commerciale", "recupero-crediti", "diritto-assicurazioni", "crisi-impresa", "real-estate", "tutela-patrimoni"],
